#include <iostream>
#include <map>
#include <string>

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 30) return 1;
    std::map<std::string, int> frequencies;
    for (std::size_t i = 0; i < count; ++i) { std::string word; if (!(std::cin >> word)) return 1; ++frequencies[word]; }
    bool first = true;
    for (const auto& [word, frequency] : frequencies) { if (!first) std::cout << ' '; first = false; std::cout << word << '=' << frequency; }
    std::cout << '\n';
}
